//go:generate go run .
//go:generate go fmt ../models/
package main

import (
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"os"
	"path/filepath"
	"strings"
	"text/template"
)

const budouxModelsBaseURL = "https://raw.githubusercontent.com/google/budoux/v0.7.0/budoux/models"

var modelTemplate = template.Must(template.New("model").Parse(`
// Code generated by gen/generate_models.go. DO NOT EDIT.
// Generate from {{.Src}}

package models

import "unique"

var {{.Name}} = func() Model {
	m := make(Model, {{len .Data}})
	{{- range $k, $g := .Data}}
	{
		g := unique.Make("{{$k}}").Value()
		features := make(map[string]float64, {{len $g}})
		{{- range $w, $s := $g}}
		features[unique.Make("{{$w}}").Value()] = {{$s}}
		{{- end}}
		m[g] = features
	}
	{{- end}}
	return m
}()
`))

func main() {
	// generate japanese model.
	if err := saveModelByName("ja"); err != nil {
		panic(err)
	}
	// generate thai model.
	if err := saveModelByName("th"); err != nil {
		panic(err)
	}
	// generate simplified chinese model.
	if err := saveModelByName("zh-hans"); err != nil {
		panic(err)
	}
	// generate traditional chinese model.
	if err := saveModelByName("zh-hant"); err != nil {
		panic(err)
	}
}

func saveModelByName(name string) error {
	d, err := loadDataByName(name)
	if err != nil {
		return err
	}
	tmp := make(map[string]map[string]int)
	if err := json.Unmarshal(d, &tmp); err != nil {
		return err
	}
	data := make(map[string]map[string]int)
	for key, group := range tmp {
		data[key] = make(map[string]int)
		for word, score := range group {
			// escape double quotes
			// thai model includes double quotes.
			word = strings.ReplaceAll(word, "\"", "\\\"")
			data[key][word] = score
		}
	}
	params := struct {
		Src  string
		Name string
		Data map[string]map[string]int
	}{
		Src:  fmt.Sprintf("%s.json", name),
		Name: strings.ReplaceAll(name, "-", ""),
		Data: data,
	}
	dst, err := getModelPathByName(name)
	if err != nil {
		return err
	}
	f, err := os.Create(dst)
	if err != nil {
		return err
	}
	defer f.Close()
	if err := modelTemplate.Execute(f, params); err != nil {
		return err
	}
	return nil
}

func loadDataByName(name string) ([]byte, error) {
	url := fmt.Sprintf("%s/%s.json", budouxModelsBaseURL, name)
	resp, err := http.Get(url)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()
	if resp.StatusCode != http.StatusOK {
		return nil, fmt.Errorf("failed to download %s: status %s", url, resp.Status)
	}
	b, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, err
	}
	return b, nil
}

func getModelPathByName(name string) (string, error) {
	fp, err := filepath.Abs(filepath.Join("..", "models", fmt.Sprintf("%s.go", name)))
	if err != nil {
		return "", err
	}
	return fp, nil
}
